steps.script:
(content) => {
  const editor = document.querySelector('div.public-DraftEditor-content[contenteditable="true"][role="textbox"]');
  if (!editor) return { success: false };
  editor.focus();
  const sel = window.getSelection();
  if (sel) {
    const range = document.createRange();
    range.selectNodeContents(editor);
    sel.removeAllRanges();
    sel.addRange(range);
  }
  let inserted = false;
  try { inserted = document.execCommand('insertHTML', false, content); } catch (e) {}
  if (!inserted || !editor.textContent || editor.textContent.trim() === '') {
    editor.innerHTML = content;
    editor.dispatchEvent(new Event('input', { bubbles: true }));
    editor.dispatchEvent(new Event('change', { bubbles: true }));
  }
  return { success: !!(editor.textContent && editor.textContent.trim() !== '') };
}
